    {
      "path": "README.md",
      "content": "# Project Structure

This project is structured as follows:

- `src/app.js`: Main application file.
- `src/server.js`: Server startup logic.
- `src/lib/errors.js`: Error handling utilities.
- `src/lib/id.js`: ID generation utilities.
- `src/modules/projects/routes.js`: Routes for projects.
- `src/modules/projects/service.js`: Service layer for projects.
- `src/modules/tasks/routes.js`: Routes for tasks.
- `src/modules/tasks/service.js`: Service layer for tasks.
- `src/modules/members/routes.js`: Routes for members.
- `src/modules/members/service.js`: Service layer for members.
- `src/modules/comments/routes.js`: Routes for comments.
- `src/modules/comments/service.js`: Service layer for comments."
    },
    {
      "path": "package.json",
      "content": "{
  "name": "project",
  "version": "1.0.0",
  "description": "A simple project management API",
  "main": "src/app.js",
  "scripts": {
    "start": "node src/server.js",
    "test": "echo \"Error: no test specified\" && exit 1"
  },
  "dependencies": {
    "express": "^4.17.3"
  },
  "devDependencies": {
    "supertest": "^6.2.4"
  }
}"
    },
    {
      "path": "src/app.js",
      "content": "const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;"
    },
    {
      "path": "src/server.js",
      "content": "const app = require('./app');
const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});"
    },
    {
      "path": "src/lib/errors.js",
      "content": "const sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};

module.exports = { sendError };"
    },
    {
      "path": "src/lib/id.js",
      "content": "const { randomUUID } = require('node:crypto');

const generateId = () => {
  return randomUUID();
};

module.exports = { generateId };"
    },
    {
      "path": "src/modules/projects/routes.js",
      "content": "const express = require('express');
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_NAME', 'Name is required');
  }
  try {
    const project = await projectsService.createProject(name);
    res.json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.get('/', async (req, res) => {
  try {
    const projects = await projectsService.getAllProjects();
    res.json({ projects });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

module.exports = router;"
    },
    {
      "path": "src/modules/projects/service.js",
      "content": "const { generateId } = require('../../lib/id');

let projectsStore = [];

const createProject = async (name) => {
  const project = { id: generateId(), name, members: [], tasks: [] };
  projectsStore.push(project);
  return project;
};

const getAllProjects = async () => {
  return projectsStore;
};

module.exports = { createProject, getAllProjects };"
    },
    {
      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { title } = req.body;
  if (!title) {
    return sendError(res, 400, 'INVALID_TITLE', 'Title is required');
  }
  try {
    const task = await tasksService.createTask(req.params.projectId, title);
    res.json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.get('/', async (req, res) => {
  const { status } = req.query;
  try {
    const tasks = await tasksService.getAllTasks(req.params.projectId, status);
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.patch('/:taskId', async (req, res) => {
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Invalid task status');
  }
  try {
    const task = await tasksService.updateTaskStatus(req.params.projectId, req.params.taskId, status);
    res.json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

module.exports = router;"
    },
    {
      "path": "src/modules/tasks/service.js",
      "content": "const { generateId } = require('../../lib/id');

let tasksStore = [];

const createTask = async (projectId, title) => {
  const task = { id: generateId(), projectId, title, status: 'todo' };
  tasksStore.push(task);
  return task;
};

const getAllTasks = async (projectId, status) => {
  let tasks = tasksStore.filter(task => task.projectId === projectId);
  if (status) {
    tasks = tasks.filter(task => task.status === status);
  }
  return tasks;
};

const updateTaskStatus = async (projectId, taskId, status) => {
  const task = tasksStore.find(task => task.id === taskId && task.projectId === projectId);
  if (!task) {
    throw new Error('Task not found');
  }
  task.status = status;
  return task;
};

module.exports = { createTask, getAllTasks, updateTaskStatus };"
    },
    {
      "path": "src/modules/members/routes.js",
      "content": "const express = require('express');
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'User ID and role are required');
  }
  try {
    const member = await membersService.addMember(req.params.projectId, userId, role);
    res.json({ member });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.get('/', async (req, res) => {
  try {
    const members = await membersService.getAllMembers(req.params.projectId);
    res.json({ members });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

module.exports = router;"
    },
    {
      "path": "src/modules/members/service.js",
      "content": "const { generateId } = require('../../lib/id');

let membersStore = [];

const addMember = async (projectId, userId, role) => {
  const member = { id: generateId(), projectId, userId, role };
  membersStore.push(member);
  return member;
};

const getAllMembers = async (projectId) => {
  return membersStore.filter(member => member.projectId === projectId);
};

module.exports = { addMember, getAllMembers };"
    },
    {
      "path": "src/modules/comments/routes.js",
      "content": "const express = require('express');
const commentsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { content } = req.body;
  if (!content) {
    return sendError(res, 400, 'INVALID_CONTENT', 'Content is required');
  }
  try {
    const comment = await commentsService.addComment(req.params.projectId, req.params.taskId, content);
    res.json({ comment });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.get('/', async (req, res) => {
  try {
    const comments = await commentsService.getAllComments(req.params.projectId, req.params.taskId);
    res.json({ comments });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

module.exports = router;"
    },
    {
      "path": "src/modules/comments/service.js",
      "content": "const { generateId } = require('../../lib/id');

let commentsStore = [];

const addComment = async (projectId, taskId, content) => {
  const comment = { id: generateId(), projectId, taskId, content };
  commentsStore.push(comment);
  return comment;
};

const getAllComments = async (projectId, taskId) => {
  return commentsStore.filter(comment => comment.projectId === projectId && comment.taskId === taskId);
};

module.exports = { addComment, getAllComments };"
    }
  ]
}
